// @gcu/sw — makeSw(config) → a self-contained classic-script sw.js string.
// Node-side (build scripts: ../works/publish pipeline, tool targets, ep/weir
// vendor-by-copy). The emitted file is the config header + sw-core.js verbatim,
// so deployed workers carry no imports and no scope quirks.
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const CORE_PATH = path.join(path.dirname(fileURLToPath(import.meta.url)), 'sw-core.js');

export function makeSw(config) {
  if (!config || !config.app) throw new Error('@gcu/sw: config.app is required');
  if (!config.cache) throw new Error('@gcu/sw: config.cache is required (version it per release)');
  if (!Array.isArray(config.precache) || !config.precache.length) {
    throw new Error('@gcu/sw: config.precache must list the app shell URLs');
  }
  for (const r of config.routes || []) {
    if (!r.strategy) throw new Error('@gcu/sw: route missing strategy');
    if (!/^(swr|network-first|cache-first|passthrough)$/.test(r.strategy)) {
      throw new Error(`@gcu/sw: unknown strategy "${r.strategy}"`);
    }
    if (!r.prefix && !r.pattern) throw new Error('@gcu/sw: route needs prefix or pattern');
    if (r.pattern) new RegExp(r.pattern);   // validate at build time, not in the field
  }
  const core = fs.readFileSync(CORE_PATH, 'utf8');
  return `// GENERATED by @gcu/sw (ext/sw/make.mjs) — edit the config in the\n`
    + `// generating build script, or sw-core.js for engine changes. Do not hand-edit.\n`
    + `const GCU_SW_CONFIG = ${JSON.stringify(config, null, 2)};\n\n`
    + core;
}
